const body = $input.first().json.body || $input.first().json;
const kbId = body.kbId;
const sourceUrl = body.sourceUrl;
const sourceBranch = body.sourceBranch || 'main';
const sourcePath = body.sourcePath || '';
const difyDatasetId = body.difyDatasetId;
const difyApiUrl = body.difyApiUrl || 'http://dify-api:5001';
const difyApiKey = body.difyApiKey || '';
const syncJobId = body.syncJobId;
const progressCallbackUrl = body.progressCallbackUrl;
const progressCallbackToken = body.progressCallbackToken || '';
const sourceToken = body.sourceToken || '';

if (!kbId || !sourceUrl || !difyDatasetId || !syncJobId || !difyApiKey) {
  throw new Error('Missing required sync parameters');
}

const match = sourceUrl.match(/github\.com\/([^/]+)\/([^/]+)/);
if (!match) throw new Error('Invalid GitHub URL: ' + sourceUrl);
const owner = match[1];
const repo = match[2].replace(/\.git$/, '');

return [{ json: {
  kbId, owner, repo,
  branch: sourceBranch,
  path: sourcePath,
  difyDatasetId, difyApiUrl, difyApiKey,
  syncJobId, progressCallbackUrl, progressCallbackToken, sourceToken,
  syncStartedAt: new Date().toISOString()
} }];

const items = $input.all();
const params = $('Parse Sync Params').first().json;
if (params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await fetch(params.progressCallbackUrl, {
      method: 'POST',
      headers,
      body: JSON.stringify({
        syncJobId: params.syncJobId,
        status: 'running',
        filesProcessed: 0,
        filesTotal: 0,
        step: {
          task: 'Fetch File Tree',
          stepName: 'fetch_file_tree',
          status: 'running',
          startedAt: params.syncStartedAt,
        },
        logMessage: `Sync started for KB ${params.kbId}`,
      }),
    });
  } catch {}
}
return items;

const tree = $input.first().json.tree || [];
const params = $('Parse Sync Params').first().json;
const basePath = (params.path || '').replace(/\/+$/, '');

const TEXT_EXTS = new Set(['md','markdown','txt','html','htm','xml','csv']);
const BINARY_EXTS = new Set(['pdf','docx','xlsx','xls','pptx','ppt','eml','msg','epub']);
const ALL_EXTS = new Set([...TEXT_EXTS, ...BINARY_EXTS]);

const files = tree.filter(item => {
  if (item.type !== 'blob') return false;
  const ext = (item.path.split('.').pop() || '').toLowerCase();
  if (!ALL_EXTS.has(ext)) return false;
  if (basePath && !item.path.startsWith(basePath + '/') && item.path !== basePath) return false;
  return true;
}).slice(0, 500);

if (files.length === 0) throw new Error('No supported files found in repository path');

return files.map((item, index) => ({ json: {
  ...params,
  filePath: item.path,
  fileSha: item.sha,
  fileExt: (item.path.split('.').pop() || '').toLowerCase(),
  fileIndex: index + 1,
  totalFiles: files.length
} }));

const items = $input.all();
const params = $('Parse Sync Params').first().json;
if (params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await fetch(params.progressCallbackUrl, {
      method: 'POST',
      headers,
      body: JSON.stringify({
        syncJobId: params.syncJobId,
        status: 'running',
        filesTotal: items.length,
        filesProcessed: 0,
        step: {
          task: 'Fetch File Tree',
          stepName: 'fetch_file_tree',
          status: 'completed',
          completedAt: new Date().toISOString(),
          message: `Found ${items.length} supported files`,
        },
        logMessage: `File tree ready: ${items.length} files to upload`,
      }),
    });
  } catch {}
}
return items;

const TEXT_EXTS = new Set(['md','markdown','txt','html','htm','xml','csv']);
const results = [];
for (const item of $input.all()) {
  const { filePath, fileExt, difyApiUrl, difyDatasetId, difyApiKey } = item.json;
  const binaryFile = item.binary && item.binary.fileData ? item.binary.fileData : null;
  const base64Content = binaryFile && binaryFile.data ? binaryFile.data : '';
  const isText = TEXT_EXTS.has(fileExt);
  let docId = null, uploadError = null;
  try {
    if (isText) {
      const text = Buffer.from(base64Content, 'base64').toString('utf8');
      const resp = await fetch(
        `${difyApiUrl}/v1/datasets/${difyDatasetId}/document/create_by_text`,
        { method: 'POST',
          headers: { 'Authorization': `Bearer ${difyApiKey}`, 'Content-Type': 'application/json' },
          body: JSON.stringify({
            name: filePath, text,
            indexing_technique: 'high_quality',
            process_rule: { mode: 'custom', rules: {
              pre_processing_rules: [
                { id: 'remove_extra_spaces', enabled: true },
                { id: 'remove_urls_emails', enabled: false }
              ],
              segmentation: { separator: '\n\n', max_tokens: 1000, chunk_overlap: 200 }
            }}
          })
        }
      );
      const data = await resp.json();
      docId = data.document?.id;
      if (!resp.ok) uploadError = data.message || `HTTP ${resp.status}`;
    } else {
      const binary = Buffer.from(base64Content, 'base64');
      const fileName = (binaryFile && binaryFile.fileName) || filePath.split('/').pop();
      const formData = new FormData();
      formData.append('file', new Blob([binary], { type: (binaryFile && binaryFile.mimeType) || 'application/octet-stream' }), fileName);
      formData.append('data', JSON.stringify({
        name: filePath,
        indexing_technique: 'high_quality',
        process_rule: { mode: 'automatic' }
      }));
      const resp = await fetch(
        `${difyApiUrl}/v1/datasets/${difyDatasetId}/document/create_by_file`,
        { method: 'POST', headers: { 'Authorization': `Bearer ${difyApiKey}` }, body: formData }
      );
      const data = await resp.json();
      docId = data.document?.id;
      if (!resp.ok) uploadError = data.message || `HTTP ${resp.status}`;
    }
  } catch (e) { uploadError = e.message; }
  results.push({ json: { ...item.json, difyDocId: docId, uploadError, uploadMethod: isText ? 'text' : 'file' } });
}
return results;

const item = $input.first();
const params = $('Parse Sync Params').first().json;
if (params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await fetch(params.progressCallbackUrl, {
      method: 'POST',
      headers,
      body: JSON.stringify({
        syncJobId: params.syncJobId,
        status: 'running',
        filesProcessed: item.json.fileIndex,
        filesTotal: item.json.totalFiles,
        chunksProcessed: item.json.fileIndex,
        step: {
          task: 'Upload Files',
          stepName: 'upload_files',
          status: 'running',
          message: `${item.json.fileIndex}/${item.json.totalFiles} uploaded`,
        },
        logMessage: `Uploaded ${item.json.filePath} via ${item.json.uploadMethod}${item.json.uploadError ? ' | ERROR: ' + item.json.uploadError : ''}`,
        logSeverity: item.json.uploadError ? 'ERROR' : 'INFO',
      }),
    });
  } catch {}
}
return [item];

const docIds = $input.all().map(item => item.json.difyDocId).filter(id => id != null);
const uploadErrors = $input.all()
  .filter(item => item.json.uploadError)
  .map(item => ({ filePath: item.json.filePath, error: item.json.uploadError }));
const params = $('Parse Sync Params').first().json;
return [{ json: { docIds, uploadErrors, params, uploadedCount: docIds.length } }];

const items = $input.all();
const summary = $input.first().json;
const params = $('Parse Sync Params').first().json;
if (params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await fetch(params.progressCallbackUrl, {
      method: 'POST',
      headers,
      body: JSON.stringify({
        syncJobId: params.syncJobId,
        status: 'running',
        step: {
          task: 'Upload Files',
          stepName: 'upload_files',
          status: 'completed',
          completedAt: new Date().toISOString(),
          message: `${summary.uploadedCount} files uploaded`,
        },
        logMessage: `All ${summary.uploadedCount} files uploaded to Dify. Starting indexing poll...`,
      }),
    });
  } catch {}
}
return items;

const items = $input.all();
const summary = $input.first().json;
const params = $('Parse Sync Params').first().json;
if (params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await fetch(params.progressCallbackUrl, {
      method: 'POST',
      headers,
      body: JSON.stringify({
        syncJobId: params.syncJobId,
        status: 'running',
        step: {
          task: 'Dify Indexing',
          stepName: 'dify_indexing',
          status: 'running',
          startedAt: new Date().toISOString(),
        },
        logMessage: `Polling Dify indexing status for ${summary.docIds.length} documents...`,
      }),
    });
  } catch {}
}
return items;

const { docIds, params, uploadErrors } = $input.first().json;
const maxAttempts = 24;
const intervalMs = 5000;
const results = {};
for (let attempt = 0; attempt < maxAttempts; attempt++) {
  await new Promise(r => setTimeout(r, intervalMs));
  let allDone = true;
  for (const docId of docIds) {
    if (results[docId] === 'completed' || results[docId] === 'error') continue;
    try {
      const resp = await fetch(
        `${params.difyApiUrl}/v1/datasets/${params.difyDatasetId}/documents/${docId}/indexing-status`,
        { headers: { 'Authorization': `Bearer ${params.difyApiKey}` } }
      );
      const data = await resp.json();
      const status = data.data?.[0]?.indexing_status;
      if (status) results[docId] = status;
      if (status !== 'completed' && status !== 'error') allDone = false;
    } catch { allDone = false; }
  }
  if (allDone) break;
}
const completedCount = Object.values(results).filter(s => s === 'completed').length;
const errorCount = Object.values(results).filter(s => s === 'error').length;
const timedOut = Object.values(results).some(s => s !== 'completed' && s !== 'error');
const hasFailures = errorCount > 0 || timedOut || (uploadErrors && uploadErrors.length > 0);
return [{ json: {
  docIds, results, completedCount, errorCount, timedOut,
  uploadErrors: uploadErrors || [],
  finalStatus: hasFailures ? 'failed' : 'completed',
  params
} }];

const items = $input.all();
const summary = $input.first().json;
const params = $('Parse Sync Params').first().json;
if (params.progressCallbackUrl) {
  const headers = { 'Content-Type': 'application/json' };
  if (params.progressCallbackToken) headers['X-Rag-Sync-Token'] = params.progressCallbackToken;
  try {
    await fetch(params.progressCallbackUrl, {
      method: 'POST',
      headers,
      body: JSON.stringify({
        syncJobId: params.syncJobId,
        status: summary.finalStatus,
        filesProcessed: summary.completedCount + summary.errorCount,
        filesTotal: summary.docIds.length,
        chunksProcessed: summary.completedCount,
        errorMessage: summary.errorCount > 0 ? `${summary.errorCount} docs failed indexing` : (summary.timedOut ? 'Indexing timed out' : ''),
        step: {
          task: 'Dify Indexing',
          stepName: 'dify_indexing',
          status: summary.finalStatus,
          completedAt: new Date().toISOString(),
          message: `${summary.completedCount} indexed, ${summary.errorCount} errors`,
        },
        logMessage: `Sync complete: ${summary.completedCount}/${summary.docIds.length} docs indexed, ${summary.errorCount} errors`,
        logSeverity: summary.finalStatus === 'failed' ? 'ERROR' : 'INFO',
      }),
    });
  } catch {}
}
return items;
